// Parse XLSX caja con exceljs. Mantiene el formato N items por fila para
// compatibilidad con Extract recargas downstream que espera $input.all().
const ExcelJS = require('exceljs');
const item = $input.first();
if (!item || !item.binary || !item.binary.data) {
  throw new Error('Sin binary del archivo de caja');
}
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
_validarXLSX(buf, (item.binary?.data?.fileName || 'archivo_caja_virtualsoft'));
const wb = new ExcelJS.Workbook();
await wb.xlsx.load(buf);
const ws = wb.worksheets[0];
if (!ws) throw new Error('Sin worksheet en caja');

const rowCount = ws.rowCount || 0;
// VALIDACION_VACIOS — Bloque hardening:
if (rowCount < 2) {
  throw new Error(`Archivo vacio o solo headers en pestana '${ws.name || 'desconocida'}' (rowCount=${rowCount}). Verifica que el XLSX tenga datos.`);
}

if (rowCount < 2) return [];

const headerRow = ws.getRow(1);
const headers = [];
const colCount = ws.columnCount || 1;
for (let c = 1; c <= colCount; c++) {
  const v = headerRow.getCell(c).value;
  headers[c - 1] = (v == null) ? '' : String(v).trim();
}

const out = [];
for (let r = 2; r <= rowCount; r++) {
  const row = ws.getRow(r);
  const obj = {};
  let allEmpty = true;
  for (let c = 1; c <= colCount; c++) {
    const h = headers[c - 1];
    if (!h) continue;
    let v = row.getCell(c).value;
    if (v && typeof v === 'object' && 'result' in v) v = v.result;
    if (v && typeof v === 'object' && 'richText' in v) v = v.richText.map(r => r.text).join('');
    if (v && v instanceof Date) v = v.toISOString().slice(0, 19).replace('T', ' ');
    obj[h] = (v == null) ? '' : v;
    if (String(v ?? '').trim() !== '') allEmpty = false;
  }
  if (!allEmpty) out.push({ json: obj });
}

return out;

// Lookup por nombre de header (no por posicion).
// Tolerante a tildes/mayusculas/orden distinto de columnas.
// Output: items con keys EXACTAS del Yopago (Fecha, ID Agencia, Valor Recarga, Banco, Confirmado)
//   asi cuando Spreadsheet File toFile escribe con headerRow=true, los datos van a las cols correctas.

function norm(s) {
  return String(s || '').trim().toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '');
}

function findKey(obj, ...candidates) {
  const keys = Object.keys(obj || {});
  for (const c of candidates) {
    const t = norm(c);
    const f = keys.find(k => norm(k) === t);
    if (f) return f;
  }
  for (const c of candidates) {
    const t = norm(c);
    const f = keys.find(k => norm(k).includes(t));
    if (f) return f;
  }
  return null;
}

const out = [];
for (const item of $input.all()) {
  const row = item.json;
  if (!row || typeof row !== 'object') continue;
  const fechaKey = findKey(row, 'Fecha');
  const idKey = findKey(row, 'ID Usuario', 'ID Agencia', 'ID');
  const valorKey = findKey(row, 'Valor');
  if (!fechaKey || !idKey || !valorKey) continue;

  const fechaCompleta = String(row[fechaKey] || '');
  const idAgencia = String(row[idKey] || '').replace(/\.0$/, '').trim();
  const valor = parseFloat(String(row[valorKey] || '0').replace(/[^0-9.\-]/g, ''));
  if (!idAgencia || !valor) continue;

  const fechaSolo = fechaCompleta.includes(' ') ? fechaCompleta.split(' ')[0] : fechaCompleta;

  // Output con headers EXACTOS del Yopago — asi se escribe correcto en xlsx
  out.push({
    "Fecha": fechaSolo,
    "ID Agencia": idAgencia,
    "Valor Recarga": valor,
    "Banco": "",
    "Confirmado": "",
  });
}
return out.map(o => ({ json: o }));

