const ahora = _fechaTest ? new Date(_fechaTest + 'T12:00:00') : new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
let _mesIdx = ahora.getMonth();
let _anio = ahora.getFullYear();
if (ahora.getDate() <= 4) {
  _mesIdx -= 1;
  if (_mesIdx < 0) { _mesIdx = 11; _anio -= 1; }
}
const sheetName = meses[_mesIdx] + ' ' + _anio;

let _hojaNueva = false;
let _plantillaSheet = null;
let ws = wb.getWorksheet(sheetName);
if (!ws) {
