const yopagoData = $('Read Yopago mes actual').first().json;
const recargasNuevas = $('Aggregate todas las filas').first().json.data || [];
const ultimaFechaYopago = yopagoData.ultimaFechaYopago || null;

function normFecha(s) {
  s = String(s == null ? '' : s).trim();
  if (!s) return '';
  s = s.split(' ')[0];
  let m = s.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/);
  if (m) return `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}`;
  m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/);
