if (fechasSel) {
  modoFiltro = 'manual';
  const selSet = new Set(fechasSel);
  for (const r of recargasNuevas) {
    const fNorm = normFecha(r['Fecha'] || r.fecha || '');
    if (fNorm && selSet.has(fNorm)) { recargasFiltradas.push(r); fechasNuevasSet.add(fNorm); }
    else { saltadas++; if (fNorm) fechasSaltadasSet.add(fNorm); }
  }
} else if (corteFecha) {
  modoFiltro = 'auto';
  for (const r of recargasNuevas) {
    const fNorm = normFecha(r['Fecha'] || r.fecha || '');
    if (fNorm && fNorm > corteFecha) { recargasFiltradas.push(r); fechasNuevasSet.add(fNorm); }
    else { saltadas++; if (fNorm) fechasSaltadasSet.add(fNorm); }
  }
} else {
  modoFiltro = 'sin_corte';
  recargasFiltradas = recargasNuevas;
  for (const r of recargasNuevas) { const f = normFecha(r['Fecha']||r.fecha||''); if (f) fechasNuevasSet.add(f); }
}

